import React from "react"
import { Logo } from "./images.js"
import { StaticQuery, graphql } from "gatsby"
import Img from "gatsby-image"
import Fade from "react-reveal/Fade"
import styled from "styled-components"

const TextContainer = styled.div`
  vertical-align: center;
  width: 80%;
  margin: 0px auto;
  margin-top: 40px;
  h1{
    color: $main-color;
    margin-top: 10px;
    margin-bottom: 0px;
    font-weight: bold;
    font-size: 20px;

    @media screen and (max-width: 480px) {
      font-size: 30px;
    }
  }
  p{
    margin: 0px;
    font-size: 12px;
    line-height: 26px;
    font-weight: lighter;
    text-align: center;
    hyphens: none;
  }
  ul {
    width: 80%;
    margin: 0px auto;
    padding: 0px;
    list-style-type: none;

    @media screen and (max-width: 480px) {
      width: 70%;
    }

  }

  li{
    cursor: pointer;
    display: inline-block;
  }
`
const Icons = styled.a`
  padding: 5px;
  margin: 5px;
  border: 1px solid #8b969b;
  border-radius: 5px;
  text-decoration: none;
  text-align: center;
  color: #8b969b;
  transition: color .75s;
  transition: border-color .75s;

  &:hover{
    color: #5A5F64;
    border-color: #5A5F64;
  }
`
const Upwork = () => (
  <StaticQuery
    query={graphql`
      query {
        placeholderImage: file(relativePath: { eq: "lumerb-upwork.png" }) {
          childImageSharp {
            fluid(maxWidth: 300) {
              ...GatsbyImageSharpFluid
            }
          }
        }
      }
    `}
    render={data => <Img style ={{width: "90px", margin: "0px auto", marginTop: "12px"}} fluid={data.placeholderImage.childImageSharp.fluid} />}
  />
)

const Hero = ()=>{

  return(

    <div name = "home" className = "lumerb-heading">
      <TextContainer>
        <Fade top>
          <Logo />
          <h1>lumerb</h1>
        </Fade>
        <Fade>
        <p>Graphic Design and Web Development</p>
        <p>View my work via</p>
        </Fade>
        <ul className="icons">
        <Fade bottom>
          <li><Icons href="https://www.behance.net/lumerbdesigns" className="fab fa-behance alt" target = "_blank" rel="noopener noreferrer"><span className="label"></span></Icons></li>
          <li><Icons href="https://www.instagram.com/lumerb_designs" className="fab fa-instagram alt" target = "_blank" rel="noopener noreferrer"><span className="label"></span></Icons></li>
          <li><Icons href="https://github.com/lumerb" className="fab fa-github alt" target = "_blank"><span className="label" rel="noopener noreferrer"></span></Icons></li>
          <li><Icons href="https://www.linkedin.com/in/lumerb" className="fab fa-linkedin alt" target = "_blank"><span className="label" rel="noopener noreferrer"></span></Icons></li>
          <li><Icons href="https://twitter.com/lumerbcode" className="fab fa-twitter alt" target = "_blank"><span className="label" rel="noopener noreferrer"></span></Icons></li>
          </Fade>
        </ul>
        <Fade bottom>
        <a href="https://www.upwork.com/fl/lumerb" target = "_blank" rel="noopener noreferrer"><Upwork /></a>
        </Fade>
      </TextContainer>
    </div>

  )
}


export default Hero
